import React, { useEffect, useState } from 'react';
import axios from 'axios';

// Mapeamento para cor dos status
const STATUS_COLORS = {
  "Recepção": "bg-red-300 text-white",
  "Solicitado": "bg-red-300 text-white",
  "Novo": "bg-teal-400 text-white",
  "Retorno": "bg-blue-400 text-white",
};

export default function ListaAgendamentos({ onEditar }) {
  const [agendamentos, setAgendamentos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
    setCarregando(true);
    axios.get('/api/agendamentos')
      .then((res) => {
        setAgendamentos(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error('Erro ao buscar agendamentos:', err);
        setCarregando(false);
      });
  }, []);

  const handleDeletar = (id) => {
    if (window.confirm('Tem certeza que deseja deletar este agendamento?')) {
      axios.delete(`/api/agendamentos/${id}`)
        .then(() => setAgendamentos(agendamentos.filter(a => a.id !== id)))
        .catch(() => alert('Erro ao deletar agendamento'));
    }
  };

  if (carregando) return <p>Carregando agendamentos...</p>;
  if (agendamentos.length === 0) return <p>Nenhum agendamento cadastrado.</p>;

  return (
    <div className="bg-white rounded-2xl shadow p-0 overflow-x-auto mt-6">
      <table className="min-w-full rounded-2xl">
        <thead>
          <tr className="border-b">
            <th className="px-4 py-3 text-left font-semibold">Operador</th>
            <th className="px-4 py-3 text-left font-semibold">Auxiliar</th>
            <th className="px-4 py-3 text-left font-semibold">Disciplina</th>
            <th className="px-4 py-3 text-left font-semibold">Paciente</th>
            <th className="px-4 py-3 text-left font-semibold">Telefone</th>
            <th className="px-4 py-3 text-left font-semibold">Data/Hora</th>
            <th className="px-4 py-3 text-left font-semibold">Status</th>
            <th className="px-4 py-3 text-left font-semibold"></th>
          </tr>
        </thead>
        <tbody>
          {agendamentos.map((ag, idx) => (
            <tr key={ag.id || idx} className="border-b last:border-b-0 hover:bg-gray-50">
              <td className="px-4 py-3">{ag.operadorNome}</td>
              <td className="px-4 py-3">{ag.auxiliarNome}</td>
              <td className="px-4 py-3">{ag.disciplinaNome}</td>
              <td className="px-4 py-3">{ag.pacienteNome}</td>
              <td className="px-4 py-3">{ag.telefone}</td>
              <td className="px-4 py-3 whitespace-nowrap">
                {ag.data && ag.hora ? (
                  <>
                    {new Date(ag.data).toLocaleDateString('pt-BR')}<br />
                    {ag.hora?.slice(0, 5)}
                  </>
                ) : "--"}
              </td>
              <td className="px-4 py-3">
                <span
                  className={
                    "inline-block px-4 py-1 rounded-full font-semibold text-sm " +
                    (STATUS_COLORS[ag.status] || "bg-gray-200 text-gray-700")
                  }
                >
                  {ag.status === "Solicitado" ? "Recepção" : ag.status}
                </span>
              </td>
              <td className="px-4 py-3 flex gap-2">
                <button
                  className="text-blue-600 hover:underline"
                  onClick={() => onEditar && onEditar(ag)}
                  title="Editar"
                >
                  Editar
                </button>
                <button
                  className="text-red-600 hover:underline"
                  onClick={() => handleDeletar(ag.id)}
                  title="Deletar"
                >
                  Deletar
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
